	(477, 208, '그레이70호텔', '경상남도 거제시 사등면 성포로 319', NULL, 'https://korean.visitkorea.or.kr/search/search_list.do?keyword=%EA%B7%B8%EB%A0%88%EC%9D%B470%ED%98%B8%ED%85%94', '3469422', '32', '숙박', 'B02', 'B0201', 'B02010900', '18:00', '12:00', '16', 'https://booking.naver.com/booking/6/bizes/326694', '가능', '{"contentid": "3469422", "contenttypeid": "32", "roomcount": "16", "roomtype": "양실", "refundregulation": "이 숙소의 취소 규정은 \\"취소 가능\\"입니다. 당일예약은 체크인 시각의 3시간전까지, 미리예약은 체크인 날짜의 1일전까지 취소 가능합니다.\\n연박예약의 경우 부분취소(일부 날짜만 취소)할 수 없습니다.\\n숙소 사정에 의한 취소 시 100% 환불 가능합니다.\\n모텔은 예약 직후 1시간 이내에는 취소가 가능합니다.(단, 예약 시점이 체크인 시간을 이미 넘긴 경우엔 15분 이내에만 취소 가능합니다.)\\n예약 직후 1시간이내라 하더라도 입실(체크인) 시간 경과 시 취소/환불 불가합니다.", "checkintime": "18:00", "checkouttime": "12:00", "chkcooking": "불가", "seminar": "0", "sports": "0", "sauna": "0", "beauty": "0", "beverage": "0", "karaoke": "0", "barbecue": "0", "campfire": "0", "bicycle": "0", "fitness": "0", "publicpc": "0", "publicbath": "0", "subfacility": "", "foodplace": "없음", "reservationurl": "https://booking.naver.com/booking/6/bizes/326694", "pickup": "불가", "infocenterlodging": "010-3862-4161", "parkinglodging": "가능", "reservationlodging": "가능", "scalelodging": "16객실", "accomcountlodging": ""}', NULL, NULL, NULL),
