INSERT INTO `transport_estimates` (`estimate_id`, `origin_text`, `destination_text`, `travel_date`, `people`, `provider`, `estimate_json`, `created_at`) VALUES
	(1, '서울역', '대전', '2026-07-02', 2, 'openai', '{"origin": "서울역", "destination": "대전", "travel_date": "2026-07-02", "people": 2, "currency": "KRW", "disclaimer": "아래 비용과 시간은 실제 예매 API가 아닌 예상 추정치임을 알려드립니다.", "options": [{"mode": "KTX (기차)", "route_summary": "서울역에서 대전역까지 KTX 직행", "estimated_time_minutes": 50, "estimated_cost_min": 54000, "estimated_cost_max": 62000, "pros": "빠른 이동, 편안한 좌석, 정시성 우수", "cons": "비용이 가장 높음"}, {"mode": "시외버스", "route_summary": "서울 고속버스터미널에서 대전 고속버스터미널까지 버스 이용, 서울역에서 버스터미널까지 지하철 이동 포함", "estimated_time_minutes": 120, "estimated_cost_min": 18000, "estimated_cost_max": 24000, "pros": "비용 저렴, 운행 빈도 높음", "cons": "교통 정체에 따른 지연 가능성, 환승 필요"}, {"mode": "자가용/택시", "route_summary": "서울역 출발하여 경부고속도로를 통해 대전까지 자가용 또는 택시 이동", "estimated_time_minutes": 90, "estimated_cost_min": 60000, "estimated_cost_max": 90000, "pros": "즉시 출발 가능, 문 앞까지 이동", "cons": "교통체증 가능성, 택시일 경우 비용 부담 큼"}], "recommended_option": "상황에 따라 다르나, 빠르고 편안한 이동을 원한다면 KTX가 좋으며, 비용 절감을 우선한다면 시외버스를 추천합니다."}', '2026-07-01 00:47:25');
